from fastapi import APIRouter

from app.controllers.search.base_search import (
	InsertRequest,
	handle_delete,
	handle_search,
)
from app.controllers.search.external.base_external import (
	CreateExternalRequest,
	handle_external_create,
	handle_external_insert,
)


def create_external_search_router(service, prefix: str, tag: str) -> APIRouter:
	"""
	Create a FastAPI router for an external search structure.

	This function acts as a router factory. It generates a complete set
	of REST endpoints that interact with an external search service.

	The service is responsible for implementing the underlying search
	algorithm (e.g., linear external search, binary external search).
	This router simply exposes the service functionality through HTTP
	endpoints.

	The router includes operations for:

	    - Creating the structure
	    - Inspecting its current state
	    - Inserting keys
	    - Searching keys
	    - Deleting keys

	Args:
	    service:
	        Instance of an external search service implementing
	        the required operations (`create`, `insert`, `search`,
	        and `delete`). The service must also expose attributes
	        such as `size`, `digits`, `block_size`, and `blocks`.

	    prefix (str):
	        URL prefix used when registering the router.

	    tag (str):
	        Tag used to group the endpoints in the OpenAPI
	        documentation generated by FastAPI.

	Returns:
	    APIRouter:
	        A configured router exposing endpoints for interacting
	        with the external search structure.

	"""
	router = APIRouter(prefix=prefix, tags=[tag])

	@router.post('/create')
	def create_structure(request: CreateExternalRequest):
		"""Create and initialize the external search structure."""
		return handle_external_create(service, request)

	@router.get('/state')
	async def get_state():
		"""Retrieve the current internal state of the structure."""
		return {
			'size': service.size,
			'digits': service.digits,
			'block_size': service.block_size,
			'blocks': service.blocks,
		}

	@router.post('/insert')
	def insert_value(request: InsertRequest):
		"""Insert a new key into the external structure."""
		return handle_external_insert(service, request)

	@router.get('/search/{value}')
	def search_value(value: str):
		"""Search for a key in the structure."""
		return handle_search(service, value)

	@router.delete('/delete/{value}')
	def delete_value(value: str):
		"""Delete a key from the structure."""
		return handle_delete(service, value)

	return router
